/**
 * Signals in message INV1_ERPM_DUTY_VOLTAGE.
 *
 * Node ID: 4 â€” ERPM, duty cycle, and DC input voltage
 *
 * All signal values are as on the CAN bus.
 */
struct fsic_inv1_erpm_duty_voltage_t {
    /**
     * Electrical RPM. ERPM = Motor_RPM * pole_pairs
     *
     * Range: -120000..120000 (-120000..120000 ERPM)
     * Scale: 1
     * Offset: 0
     */
    int32_t inv1_actual_erpm;

    /**
     * Controller duty cycle. Positive=motoring, negative=regen
     *
     * Range: -1000..1000 (-100..100 %)
     * Scale: 0.1
     * Offset: 0
     */
    int16_t inv1_actual_duty;

    /**
     * DC bus input voltage
     *
     * Range: 0..1000 (0..1000 V)
     * Scale: 1
     * Offset: 0
     */
    int16_t inv1_actual_input_voltage;
};

/**
 * Signals in message INV1_AC_DC_current.
 *
 * Node ID: 4 â€” AC and DC current
 *
 * All signal values are as on the CAN bus.
 */
struct fsic_inv1_ac_dc_current_t {
    /**
     * Motor AC current. Positive=motoring, negative=regen
     *
     * Range: -8500..8500 (-850..850 Apk)
     * Scale: 0.1
     * Offset: 0
     */
    int16_t inv1_actual_ac_current;

    /**
     * DC side current. Positive=motoring, negative=regen
     *
     * Range: -8500..8500 (-850..850 A)
     * Scale: 0.1
     * Offset: 0
     */
    int16_t inv1_actual_dc_current;
};

